@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  html {
    @apply bg-surface text-on-surface;
    scroll-behavior: smooth;
  }

  body {
    @apply font-body antialiased overflow-x-hidden;
    background-color: #0c1322;
    color: #dce2f8;
  }

  ::selection {
    @apply bg-primary text-on-primary;
  }
}

@layer components {
  .material-symbols-outlined {
    font-variation-settings: 'FILL' 0, 'wght' 300, 'GRAD' 0, 'opsz' 24;
    font-family: 'Material Symbols Outlined';
    font-style: normal;
    display: inline-block;
    vertical-align: middle;
    line-height: 1;
    letter-spacing: normal;
    text-transform: none;
    white-space: nowrap;
    word-wrap: normal;
    -webkit-font-feature-settings: 'liga';
    font-feature-settings: 'liga';
    -webkit-font-smoothing: antialiased;
  }

  .grid-bg {
    background-image: radial-gradient(circle at 2px 2px, rgba(233, 193, 118, 0.05) 1px, transparent 0);
    background-size: 40px 40px;
  }

  .ghost-grid {
    background-image: radial-gradient(circle, #45464c 1px, transparent 1px);
    background-size: 32px 32px;
    opacity: 0.1;
  }

  .ghost-border {
    border: 1px solid rgba(69, 70, 76, 0.2);
  }

  .hero-gradient {
    background: linear-gradient(180deg, rgba(12, 19, 34, 0) 0%, rgba(12, 19, 34, 1) 100%);
  }

  .glass-header {
    background: rgba(12, 19, 34, 0.85);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
  }
}
